func startsWithEmoji(text string) bool {
	text = strings.TrimSpace(text)
	if text == "" {
		return false
	}
	r, _ := utf8.DecodeRuneInString(text)
	return r == '©' ||
		r == '®' ||
		(r >= 0x203C && r <= 0x3299) ||
		(r >= 0x1F000 && r <= 0x1FAFF)
}

func relevantEventEmoji(parts ...string) string {
	text := strings.ToLower(strings.Join(parts, " "))
	switch {
	case containsAny(text, "doctor", "dentist", "clinic", "hospital", "therapy", "physio", "appointment"):
		return "🏥"
	case containsAny(text, "flight", "airport", "plane"):
		return "✈️"
	case containsAny(text, "train", "bahn", "station"):
		return "🚆"
	case containsAny(text, "birthday"):
		return "🎂"
	case containsAny(text, "coffee", "cafe"):
		return "☕"
	case containsAny(text, "dinner", "lunch", "breakfast", "brunch", "restaurant"):
		return "🍽️"
	case containsAny(text, "gym", "workout", "run", "yoga", "fitness"):
		return "🏃"
	case containsAny(text, "concert", "show", "movie", "theater", "theatre", "party"):
		return "🎟️"
	case containsAny(text, "call", "meeting", "sync", "standup", "interview", "1:1"):
		return "💬"
	case containsAny(text, "deadline", "reminder", "due"):
		return "⏰"
	case containsAny(text, "office", "work"):
		return "💼"
	case containsAny(text, "home"):
		return "🏠"
	default:
		return "📅"
	}
}

func containsAny(text string, needles ...string) bool {
	for _, needle := range needles {
		if strings.Contains(text, needle) {
			return true
		}
	}
	return false
}
